const item = $input.first().json;
const video_id = item.video_id || null;
if (!video_id) throw new Error('video_id não encontrado.');
return [{ json: { video_id } }];

const config = $('Configuração').first().json;
const nvId = config.NETWORK_VOLUME_ID;
const createBody = {
  query: `mutation { podFindAndDeployOnDemand(input: { name: "clay-comfyui", cloudType: SECURE, gpuTypeId: "NVIDIA A40", gpuCount: 1, containerDiskInGb: 10, networkVolumeId: "${nvId}", ports: "8188/http,8080/http,8888/http", volumeMountPath: "/workspace", imageName: "runpod/comfyui:latest" }) { id desiredStatus } }`
};
return [{ json: { createBody } }];

const response = $input.first().json;
if (response.errors && response.errors.length > 0) {
  throw new Error('RunPod API erro: ' + response.errors.map(e => e.message).join('; '));
}
const newPodId = response?.data?.podFindAndDeployOnDemand?.id;
if (!newPodId) throw new Error('Falha ao criar pod: ' + JSON.stringify(response));
var staticData = $getWorkflowStaticData('global');
staticData.podId = newPodId;
staticData.comfyuiUrl = 'https://' + newPodId + '-8188.proxy.runpod.net';
staticData.podRetries = 0;
return [{ json: { podId: newPodId, comfyuiUrl: staticData.comfyuiUrl } }];

var response = $('Checar Pod').first().json;
var staticData = $getWorkflowStaticData('global');
staticData.podRetries = (staticData.podRetries || 0) + 1;
var running = false;
try { var status = response.data.pod.desiredStatus; var uptime = response.data.pod.runtime.uptimeInSeconds; running = (status === 'RUNNING' && uptime > 0); } catch(e) {}
return [{ json: { _podReady: running, _podTimeout: (!running && staticData.podRetries >= 20) } }];

var staticData = $getWorkflowStaticData('global');
staticData.comfyRetries = 0;
return [{ json: { checkUrl: staticData.comfyuiUrl + '/object_info' } }];

var response = $('Checar ComfyUI').first().json;
var staticData = $getWorkflowStaticData('global');
staticData.comfyRetries = (staticData.comfyRetries || 0) + 1;
var ready = false;
try {
  var keys = Object.keys(response);
  var hasNodes = keys.length > 50;
  var hasTTS = response.hasOwnProperty('FB_Qwen3TTSVoiceClone');
  var hasSaveMP3 = response.hasOwnProperty('SaveAudioMP3');
  ready = hasNodes && hasTTS && hasSaveMP3;
} catch(e) {}
return [{ json: { _comfyReady: ready, _comfyTimeout: (!ready && staticData.comfyRetries >= 40) } }];

const cenaItems = $('Ler Cenas').all().map(i => i.json);
const cenas = Array.isArray(cenaItems[0]) ? cenaItems[0] : cenaItems;
const videoId = $('Normalizar Input').first().json.video_id;
return cenas.map(c => ({ json: { ...c, _videoId: videoId } }));

const item = $('Loop Cenas').first().json;
var staticData = $getWorkflowStaticData('global');
const comfyuiUrl = staticData.comfyuiUrl;
const seed = Math.floor(Math.random() * 999999999999999);

const VOICE_MAP = {
  calma: { audio: 'Calma.mp3', ref_text: 'Esta é uma história que aconteceu numa pequena cidade do interior. Ninguém fala sobre isso. Mas todo mundo lembra. E todo mundo tem medo.' },
  neutra: { audio: 'Neutro.mp3', ref_text: 'Naquela noite, eu ouvi passos no corredor. Lentos, pesados, arrastados. Quando abri a porta, não havia ninguém. Mas as pegadas no chão ainda estavam quentes.' },
  tensa: { audio: 'Tensa.mp3', ref_text: 'Ele não devia ter atendido aquele telefone. Alguma coisa estava errada. A voz do outro lado não era humana. Ele sabia disso. Mas não conseguia desligar.' },
  suspense: { audio: 'Suspense.mp3', ref_text: 'Tem algo embaixo da cama. Eu sei porque consigo sentir a respiração. Está quente. Está perto. E está esperando eu colocar os pés no chão.' },
  panico: { audio: 'Panico.mp3', ref_text: 'Corre! Não olha pra trás! Aquilo não é a sua mãe! Eu vi o rosto daquela coisa e não era humano! Pelo amor de Deus, não abre essa porta!' }
};

const emocao = item.emocao || 'neutra';
const voice = VOICE_MAP[emocao] || VOICE_MAP.neutra;

const payload = {
  "24": { "inputs": { "audio": voice.audio }, "class_type": "LoadAudio", "_meta": { "title": "Load Audio" } },
  "40": { "inputs": { "target_text": item.narracao, "model_choice": "1.7B", "device": "auto", "precision": "bf16", "language": "Portuguese", "ref_text": voice.ref_text, "seed": seed, "max_new_tokens": 2048, "top_p": 0.8, "top_k": 20, "temperature": 1, "repetition_penalty": 1.05, "x_vector_only": false, "attention": "sdpa", "unload_model_after_generate": false, "custom_model_path": "", "ref_audio": ["24", 0] }, "class_type": "FB_Qwen3TTSVoiceClone", "_meta": { "title": "\ud83c\udfad Qwen3-TTS VoiceClone" } },
  "41": { "inputs": { "filename_prefix": "Narr_" + (item.numero || 'unknown'), "quality": "V0", "audio": ["40", 0] }, "class_type": "SaveAudioMP3", "_meta": { "title": "Save Audio (MP3)" } }
};

return [{ json: { promptUrl: comfyuiUrl + '/prompt', promptBody: { prompt: payload }, cenaId: item.id, cenaNumero: item.numero, videoId: item._videoId, emocao: emocao } }];

var response = $input.first().json;
var staticData = $getWorkflowStaticData('global');
var meta = $('Montar Payload TTS').first().json;
var promptId = response.prompt_id;
staticData.audioPromptId = promptId;
staticData.audioHistoryUrl = staticData.comfyuiUrl + '/history/' + promptId;
staticData.audioRetries = 0;
return [{ json: { promptId: promptId, cenaId: meta.cenaId, cenaNumero: meta.cenaNumero, videoId: meta.videoId, emocao: meta.emocao } }];

var input = $('Buscar Resultado').first().json;
var staticData = $getWorkflowStaticData('global');
var promptId = staticData.audioPromptId;
staticData.audioRetries = (staticData.audioRetries || 0) + 1;

var pronto = false;
var filename = null;
var erro = false;
var erroMsg = '';

try {
  var hist = input[promptId];
  if (hist) {
    // DETECTAR ERRO
    if (hist.status && hist.status.status_str === 'error') {
      erro = true;
      var msgs = hist.status.messages || [];
      for (var m = 0; m < msgs.length; m++) {
        if (msgs[m][0] === 'execution_error') {
          erroMsg = msgs[m][1].exception_message || 'Erro desconhecido';
          break;
        }
      }
      if (!erroMsg) erroMsg = 'ComfyUI status: error';
    }
    // DETECTAR SUCESSO
    if (!erro && hist.outputs) {
      var keys = Object.keys(hist.outputs);
      for (var k = 0; k < keys.length; k++) {
        var nodeOut = hist.outputs[keys[k]];
        if (nodeOut.audio && nodeOut.audio.length > 0) {
          filename = nodeOut.audio[0].filename;
          pronto = true;
          break;
        }
      }
    }
  }
} catch(e) {}

var meta = $('Preparar Polling Audio').first().json;

return [{ json: {
  _ready: pronto,
  _erro: erro,
  _erroMsg: erroMsg,
  _timeout: (!pronto && !erro && staticData.audioRetries >= 60),
  filename: filename,
  downloadUrl: pronto ? (staticData.comfyuiUrl + '/view?filename=' + encodeURIComponent(filename) + '&type=output') : null,
  cenaId: meta.cenaId,
  cenaNumero: meta.cenaNumero,
  videoId: meta.videoId,
  emocao: meta.emocao
} }];

var staticData = $getWorkflowStaticData('global');
var podId = staticData.podId || 'unknown';
var erroMsg = $input.first().json._erroMsg || $input.first().json.erro || 'Timeout sem resultado';
return [{ json: {
  stopBody: { query: 'mutation { podTerminate(input: {podId: "' + podId + '"}) }' },
  erro: 'TTS FALHOU: ' + erroMsg + ' | AÇÃO: Rode post_boot.sh via JupyterLab (8888) e re-execute.'
} }];

const meta = $input.first().json;
const config = $('Configuração').first().json;
const storagePath = meta.videoId + '/narr_' + meta.cenaNumero + '.mp3';
const publicUrl = config.SUPABASE_URL + '/storage/v1/object/public/narracoes/' + storagePath;
return [{ json: { downloadUrl: meta.downloadUrl, uploadUrl: config.SUPABASE_URL + '/storage/v1/object/narracoes/' + storagePath, publicUrl: publicUrl, cenaId: meta.cenaId, cenaNumero: meta.cenaNumero, videoId: meta.videoId, supabaseKey: config.SUPABASE_SERVICE_KEY } }];

const meta = $('Prep Download').first().json;

const response = await this.helpers.httpRequest({
  method: 'GET',
  url: meta.downloadUrl,
  encoding: 'arraybuffer',
  returnFullResponse: true,
});

const buffer = Buffer.from(response.body);

let duration = 0;
try {
  const brV1L3 = [0,32,40,48,56,64,80,96,112,128,160,192,224,256,320,0];
  const brV2L3 = [0,8,16,24,32,40,48,56,64,80,96,112,128,144,160,0];
  const srV1 = [44100,48000,32000];
  const srV2 = [22050,24000,16000];
  let frameCount = 0; let sampleRate = 24000; let samplesPerFrame = 576; let pos = 0;
  while (pos < buffer.length - 4) {
    if (buffer[pos] === 0xFF && (buffer[pos + 1] & 0xE0) === 0xE0) {
      const header = buffer.readUInt32BE(pos);
      const mpegVer = (header >> 19) & 3;
      const brIdx = (header >> 12) & 15;
      const srIdx = (header >> 10) & 3;
      const padding = (header >> 9) & 1;
      let br, sr, spf, frameLen;
      if (mpegVer === 3) { br = brV1L3[brIdx]*1000; sr = srIdx<3?srV1[srIdx]:44100; spf=1152; frameLen=br>0?Math.floor((144*br)/sr)+padding:0; }
      else { br = brV2L3[brIdx]*1000; sr = srIdx<3?srV2[srIdx]:24000; spf=576; frameLen=br>0?Math.floor((72*br)/sr)+padding:0; }
      if (frameLen > 0) { frameCount++; sampleRate=sr; samplesPerFrame=spf; pos+=frameLen; } else { pos++; }
    } else { pos++; }
  }
  if (frameCount > 0 && sampleRate > 0) { duration = (frameCount * samplesPerFrame) / sampleRate; }
} catch(e) {}

duration = Math.round(duration * 100) / 100;

const binaryData = await this.helpers.prepareBinaryData(buffer, 'audio.mp3', 'audio/mpeg');

return [{ json: { duracao_real: duration }, binary: { data: binaryData } }];

